// 定义 Schema 和 Resolver
const { ApolloServer, gql } = require('apollo-server');

const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: User!
  }

  type Query {
    getUser(id: ID!): User
    getPosts(userId: ID): [Post!]
  }
`;

const resolvers = {
  Query: {
    getUser: (parent, { id }) => users.find(user => user.id === id),
    getPosts: (parent, { userId }) => posts.filter(post => post.authorId === userId)
  }
};

const server = new ApolloServer({ typeDefs, resolvers });
server.listen().then(({ url }) => console.log(`服务运行在 ${url}`));

// 测试一个简单的工具函数
function sum(a, b) {
  return a + b;
}

// 测试用例
describe('sum 函数', () => {
  test('1 + 2 应该等于 3', () => {
    expect(sum(1, 2)).toBe(3);
  });

  test('负数相加正确', () => {
    expect(sum(-1, -2)).toBe(-3);
  });

  test('零相加正确', () => {
    expect(sum(0, 0)).toBe(0);
  });
});

